import kotlin.collections.PriorityQueue
import java.util.LinkedList
import java.util.*

fun solve(c: Long, connections: Array<Array<Long>>, queries: Array<Array<Long>>): Array<Long> {
    val graph = MutableList(c.toInt() + 1) { mutableListOf<Long>() }
    for (connection in connections) {
        val u = connection[0]
        val v = connection[1]
        graph[u.toInt()].add(v)
        graph[v.toInt()].add(u)
    }

    val visited = BooleanArray(c.toInt() + 1) { false }
    val components = mutableListOf<MutableList<Long>>()
    for (node in 1..c.toInt()) {
        if (!visited[node]) {
            val component = mutableListOf<Long>()
            val queue = LinkedList<Long>()
            queue.add(node)
            visited[node] = true
            while (queue.isNotEmpty()) {
                val current = queue.pollFirst()
                component.add(current)
                for (neighbor in graph[current.toInt()]) {
                    if (!visited[neighbor.toInt()]) {
                        visited[neighbor.toInt()] = true
                        queue.add(neighbor)
                    }
                }
            }
            components.add(component)
        }
    }

    val componentHeaps = Array(components.size) { PriorityQueue<Long>() }
    for (i in 0 until components.size) {
        val nodes = components[i]
        for (node in nodes) {
            componentHeaps[i].add(node)
        }
    }

    val online = BooleanArray(c.toInt() + 1) { true }
    val componentId = Array(c.toInt() + 1) { -1L }
    for (i in 0 until components.size) {
        for (node in components[i]) {
            componentId[node.toInt()] = i.toLong()
        }
    }

    val result = mutableListOf<Long>()
    for (query in queries) {
        when (query[0]) {
            1L -> {
                val x = query[1]
                if (online[x.toInt()]) {
                    result.add(x)
                } else {
                    val comp = componentId[x.toInt()]
                    if (comp == -1L) {
                        result.add(-1L)
                    } else {
                        var current: Long? = null
                        while (componentHeaps[comp.toInt()].size > 0) {
                            current = componentHeaps[comp.toInt()].peek()
                            if (online[current!!.toInt()]) {
                                break
                            } else {
                                componentHeaps[comp.toInt()].poll()
                            }
                        }
                        if (current != null) {
                            result.add(current)
                        } else {
                            result.add(-1L)
                        }
                    }
                }
            }
            2L -> {
                val x = query[1]
                online[x.toInt()] = false
            }
        }
    }
    return result.toLongArray()
}
