import kotlin.collections.TreeSet

fun solve(c: Long, connections: Array<Array<Long>>, queries: Array<Array<Long>>): Array<Long> {
    val parent = LongArray(c + 1)
    val rank = LongArray(c + 1)
    for (i in 1..c) {
        parent[i] = i
        rank[i] = 1
    }

    fun find(x: Long): Long {
        if (parent[x] != x) {
            parent[x] = find(parent[x])
        }
        return parent[x]
    }

    fun union(x: Long, y: Long) {
        val rootX = find(x)
        val rootY = find(y)
        if (rootX != rootY) {
            if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY
            } else {
                parent[rootY] = rootX
                if (rank[rootX] == rank[rootY]) {
                    rank[rootX] += 1
                }
            }
        }
    }

    for (conn in connections) {
        val u = conn[0]
        val v = conn[1]
        union(u, v)
    }

    val componentMap = mutableMapOf<Long, TreeSet<Long>>()
    for (i in 1..c) {
        val root = find(i)
        componentMap.getOrPut(root) { TreeSet<Long>() }.add(i)
    }

    val isOnline = BooleanArray(c + 1).apply { fill(true) }

    val result = mutableListOf<Long>()
    for (query in queries) {
        when (query[0]) {
            1L -> {
                val x = query[1]
                if (isOnline[x]) {
                    result.add(x)
                } else {
                    val root = find(x)
                    val componentSet = componentMap[root] ?: TreeSet<Long>()
                    if (componentSet.isEmpty()) {
                        result.add(-1L)
                    } else {
                        result.add(componentSet.first())
                    }
                }
            }
            2L -> {
                val x = query[1]
                isOnline[x] = false
                val root = find(x)
                val componentSet = componentMap[root] ?: TreeSet<Long>()
                componentSet.remove(x)
            }
        }
    }

    return result.toLongArray()
}
